FROM jsonb_to_recordset('[{"id": "cap-114-chinese-001", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "\b\n根據資料，右側詐騙簡訊使用了哪一種話術？", "options": ["", "", "", ""], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image", "option_incomplete", "option_image"], "parse_confidence": 0.25, "original_question_number": 1, "raw_text": "1.                                    \b\n\n\n\n\n     根據資料，右側詐騙簡訊使用了哪一種話術？\n     (A)  (B)  (C)   (D)\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-chinese-002", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "「清代驗屍跟現代不同，驗屍一定是在『屍所』，即屍體所在之處，可能是案\n發現場，也可能是陳屍處。清代的程序非常強調在屍所驗屍，禁止將屍體帶到\n他處檢驗。同時十分強調涉案人、關係人和家屬必須在場，一般大眾也可以圍\n觀。目的在於使驗屍過程中，關於屍傷屍狀的觀察都能夠『公同一干人眾，質\n對明白』。」若要拍攝清代刑案電視劇，下列情節何者最符合本文的敘述？", "options": ["將屍體從案發現場帶至衙門驗屍", "官府開始驗屍時，家屬必須到場", "驗屍時將一干閒雜人等驅離現場", "家屬要求確認結果，被斷然拒絕"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.   「清代驗屍跟現代不同，驗屍一定是在『屍所』，即屍體所在之處，可能是案\n     發現場，也可能是陳屍處。清代的程序非常強調在屍所驗屍，禁止將屍體帶到\n     他處檢驗。同時十分強調涉案人、關係人和家屬必須在場，一般大眾也可以圍\n     觀。目的在於使驗屍過程中，關於屍傷屍狀的觀察都能夠『公同一干人眾，質\n     對明白』。」若要拍攝清代刑案電視劇，下列情節何者最符合本文的敘述？\n     (A)將屍體從案發現場帶至衙門驗屍\n     (B)官府開始驗屍時，家屬必須到場\n     (C)驗屍時將一干閒雜人等驅離現場\n     (D)家屬要求確認結果，被斷然拒絕\n\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "原文「同時十分強調涉案人、關係人和家屬必須在場」明白指出家屬必須到場，故 (B) 正確。(A) 違反「禁止將屍體帶到他處檢驗」；(C) 違反「一般大眾也可以圍觀」；(D) 文中無此敘述。"}, {"id": "cap-114-chinese-003", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "根據下表中的字形，何者的造字原則與「月」字相同？", "options": ["小", "木", "出", "汝"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 3, "raw_text": "3.   根據下表中的字形，何者的造字原則與「月」字相同？\n\n\n\n\n     (A)小   (B)木   (C)出   (D)汝\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-chinese-004", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "關於右側這首詩的解讀，下列何者最恰當？", "options": ["悲傷會過去，快樂會留下", "我的快樂等同於我的悲傷", "除了悲傷之外，我一無所有", "每個人的愛情都只有一種結果"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 4, "raw_text": "4.   關於右側這首詩的解讀，下列何者最恰當？\n     (A)悲傷會過去，快樂會留下\n     (B)我的快樂等同於我的悲傷\n     (C)除了悲傷之外，我一無所有\n     (D)每個人的愛情都只有一種結果\n\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-chinese-005", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "東漢 許慎《說文解字》收錄的字體以小篆為主，兼採秦以前的古文字與籀文。\n下列四個不同字體的「封」字，何者不會收錄在其中？\n࠾", "options": ["", "", "", ""], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 5, "raw_text": "5.       東漢 許慎《說文解字》收錄的字體以小篆為主，兼採秦以前的古文字與籀文。\n         下列四個不同字體的「封」字，何者不會收錄在其中？\n\n           ࠾"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-chinese-006", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "根據以上資料，下列推論何者最恰當？", "options": ["因疫情而封城，易誘發潛在的家庭暴力", "疫情期間女性受家暴後通報的意願較高", "家庭壓力上升造成女性收入與行動受限", "過度關注疫情，導致政府漠視性別平權"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.\n\n\n\n\n         根據以上資料，下列推論何者最恰當？\n         (A)因疫情而封城，易誘發潛在的家庭暴力\n         (B)疫情期間女性受家暴後通報的意願較高\n         (C)家庭壓力上升造成女性收入與行動受限\n         (D)過度關注疫情，導致政府漠視性別平權\n\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "本題搭配資料圖表（pdftotext 未抽到）。從選項判斷，研究普遍指出封城使受害者與施暴者長期共處，潛在家暴更易爆發，故 (A) 正確。"}, {"id": "cap-114-chinese-007", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "Ĵ                     Ĵ\nĳ           Ĳ\nĳ                Ĳ\n根據甲、乙二圖，下列敘述何者最恰當？", "options": ["皆指出如何區分漢語的聲調", "皆指出對聯「仄起平收」的原則", "皆說明貼的順序為上聯 → 橫批 → 下聯", "皆說明站在屋外、面向大門的右邊要貼下聯"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7.\n\n\n                     Ĵ                     Ĵ\n\n                                   ĳ           Ĳ\n\n\n\n     ĳ                Ĳ\n\n\n\n\n         根據甲、乙二圖，下列敘述何者最恰當？\n         (A)皆指出如何區分漢語的聲調\n         (B)皆指出對聯「仄起平收」的原則\n         (C)皆說明貼的順序為上聯 → 橫批 → 下聯\n         (D)皆說明站在屋外、面向大門的右邊要貼下聯\n\n\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "本題搭配甲乙二圖（pdftotext 未抽到）。從選項判斷，對聯張貼的核心通則是「仄起平收」原則，故 (B) 正確。"}, {"id": "cap-114-chinese-008", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "貫雲石〈小梁州〉秋\n芙蓉映水菊花黃，滿目秋光。枯荷葉底鷺鷥藏。金風盪，飄動桂枝香。\n雷峰塔畔登高望，見錢塘一派長江。湖水清，江潮漾。天邊斜月，新雁兩三行。\n關於這首曲的分析，下列何者最恰當？", "options": ["題目為〈小梁州〉，是散曲中的小令", "在曲作的中間換韻，不是一韻到底", "以「菊花」、「金風」、「桂枝」呼應「秋」", "以「斜月」、「新雁」象徵世間繁華轉眼成空"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8.\n     貫雲石〈小梁州〉秋\n       芙蓉映水菊花黃，滿目秋光。枯荷葉底鷺鷥藏。金風盪，飄動桂枝香。\n     雷峰塔畔登高望，見錢塘一派長江。湖水清，江潮漾。天邊斜月，新雁兩三行。\n     關於這首曲的分析，下列何者最恰當？\n     (A)題目為〈小梁州〉，是散曲中的小令\n     (B)在曲作的中間換韻，不是一韻到底\n     (C)以「菊花」、「金風」、「桂枝」呼應「秋」\n     (D)以「斜月」、「新雁」象徵世間繁華轉眼成空\n\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "曲中「菊花黃」、「金風盪」、「桂枝香」皆為秋天意象，緊扣題目〈秋〉，故 (C) 正確。(A)〈小梁州〉是曲牌名而非題目；(B) 全曲一韻到底（陽韻）；(D)「斜月」「新雁」屬秋景白描，非繁華成空。"}, {"id": "cap-114-chinese-009", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "中式花茶依加工方式，可分為三種：第一種是成品內沒有花但香氣濃郁\n的茶，如茉莉花茶；第二種是成品內有花的茶，如玫瑰烏龍茶；第三種是純\n花茶，成品內沒有茶葉，如菊花茶、蓮花茶等。其中第一種等級最高，又稱\n「香片」。香片是將乾燥後的茶葉與新鮮的香花依比例混合，靜置陰涼處，等\n茶葉吸收花的香氣後將花篩除，再烘乾製成。\n根據本文，下列花茶店店員針對顧客需求所給的建議，何者不恰當？", "options": ["", "", "", ""], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 9, "raw_text": "9.\n       中式花茶依加工方式，可分為三種：第一種是成品內沒有花但香氣濃郁\n     的茶，如茉莉花茶；第二種是成品內有花的茶，如玫瑰烏龍茶；第三種是純\n     花茶，成品內沒有茶葉，如菊花茶、蓮花茶等。其中第一種等級最高，又稱\n     「香片」。香片是將乾燥後的茶葉與新鮮的香花依比例混合，靜置陰涼處，等\n     茶葉吸收花的香氣後將花篩除，再烘乾製成。\n     根據本文，下列花茶店店員針對顧客需求所給的建議，何者不恰當？\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-chinese-010", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "「蜂造之蜜出山崖、土穴者十居其八，而人家招蜂造釀而割取者，十居其二\n也。北方乾燥，土穴所釀多出於此。南方卑溼，故有崖蜜而無穴蜜。西北半天\n下，蓋與蔗漿分勝云。」根據本文，下列推論何者最恰當？", "options": ["穴蜜多產於乾燥之處", "崖蜜多為人工養育而來", "卑溼之地沒有天然的蜂造之蜜", "西北蜂蜜產量是東南蔗漿的一半"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 10, "raw_text": "10. 「蜂造之蜜出山崖、土穴者十居其八，而人家招蜂造釀而割取者，十居其二\n    也。北方乾燥，土穴所釀多出於此。南方卑溼，故有崖蜜而無穴蜜。西北半天\n    下，蓋與蔗漿分勝云。」根據本文，下列推論何者最恰當？\n    (A)穴蜜多產於乾燥之處\n    (B)崖蜜多為人工養育而來\n    (C)卑溼之地沒有天然的蜂造之蜜\n    (D)西北蜂蜜產量是東南蔗漿的一半\n\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "原文「北方乾燥，土穴所釀多出於此」明指穴蜜多產於乾燥之處，故 (A) 正確。(B) 崖蜜為山崖自然所造（十居其八），非人工；(C) 卑溼之地有崖蜜；(D) 文中未提及產量比例。"}, {"id": "cap-114-chinese-011", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "「旅行回來，一篇遊記常要寫上許久，有的終究沒寫成。有時不知怎麼濃縮剪\n裁，最後只是一片凌亂的札記和草稿。那些沒寫出來的，只好留待時間去處理\n了。時間如果不是個偉大的作者，起碼是個傑出的編輯。也許它最後會告訴\n我：不寫也罷！」根據文意脈絡，關於畫線處文句的解讀，下列何者最恰當？", "options": ["真正優秀的作品，經得起時間的考驗", "要寫出一篇好遊記，作者比編輯更重要", "成為傑出的編輯，需要時間與經驗的累積", "經過時間的沉澱，自然能釐清值得寫的是什麼"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 「旅行回來，一篇遊記常要寫上許久，有的終究沒寫成。有時不知怎麼濃縮剪\n    裁，最後只是一片凌亂的札記和草稿。那些沒寫出來的，只好留待時間去處理\n    了。時間如果不是個偉大的作者，起碼是個傑出的編輯。也許它最後會告訴\n    我：不寫也罷！」根據文意脈絡，關於畫線處文句的解讀，下列何者最恰當？\n    (A)真正優秀的作品，經得起時間的考驗\n    (B)要寫出一篇好遊記，作者比編輯更重要\n    (C)成為傑出的編輯，需要時間與經驗的累積\n    (D)經過時間的沉澱，自然能釐清值得寫的是什麼\n\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "畫線句「時間如果不是個偉大的作者，起碼是個傑出的編輯」以「編輯」比喻時間具有篩選功能，能幫作者釐清哪些素材值得保留或捨棄，故 (D) 正確。"}, {"id": "cap-114-chinese-012", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "「我的本行是科學而非文學甲  甲 也許這正是我的缺失乙 乙 也許這反而是我的長處，\n無論如何我清楚明白丙丙 科學需要人文的關懷丁  丁 而文學需要理性的自覺。」根據\n文意脈絡，甲乙丙丁四處，何者最適合填入標點符號中的冒號？", "options": ["甲", "乙", "丙", "丁"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 「我的本行是科學而非文學甲  甲 也許這正是我的缺失乙 乙 也許這反而是我的長處，\n    無論如何我清楚明白丙丙 科學需要人文的關懷丁  丁 而文學需要理性的自覺。」根據\n    文意脈絡，甲乙丙丁四處，何者最適合填入標點符號中的冒號？\n    (A)甲 (B)乙  (C)丙    (D)丁\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "冒號用於提示後文。「我清楚明白丙：科學需要人文的關懷……文學需要理性的自覺」— 冒號引出「我清楚明白」之後的具體內容，故填於丙處最恰當。"}, {"id": "cap-114-chinese-013", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "下列文句中的語詞，何者使用最恰當？", "options": ["他奮力救人的義舉，淪為一段佳話", "我如此盡心，既然得到這樣的待遇", "此建案已延宕多時，如今終於竣工", "那件事能夠完成，不愧有你的幫忙"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. 下列文句中的語詞，何者使用最恰當？\n    (A)他奮力救人的義舉，淪為一段佳話\n    (B)我如此盡心，既然得到這樣的待遇\n    (C)此建案已延宕多時，如今終於竣工\n    (D)那件事能夠完成，不愧有你的幫忙\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "(C)「竣工」用於工程完成，搭配「建案」、「延宕多時」語意通順。(A)「淪為」帶貶義不合「義舉」；(B) 應為「竟然」非「既然」；(D) 應為「全靠」或「多虧」。"}, {"id": "cap-114-chinese-014", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-114-chinese", "question_type": "single_choice", "question_text": "下列文句「」中的字，何者讀音正確？", "options": ["有些玩笑話沒拿捏好分寸，就可能變成「揶」揄：ㄧㄝˊ", "這家賣場備有各種「晾」晒工具，提供消費者選購：ㄐㄧㄥ", "這齣音樂劇結合不同族群的元素，打破文化的「藩」籬：ㄆㄢ", "原以為勝券在握，卻因一時疏忽，竟從雲端「栽」了下來：ㄘㄞˊ"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:58:12+00:00", "source_pdf_sha1": "29771b95c3d8", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 下列文句「」中的字，何者讀音正確？\n    (A)有些玩笑話沒拿捏好分寸，就可能變成「揶」揄：ㄧㄝˊ\n    (B)這家賣場備有各種「晾」晒工具，提供消費者選購：ㄐㄧㄥ\n    (C)這齣音樂劇結合不同族群的元素，打破文化的「藩」籬：ㄆㄢ\n    (D)原以為勝券在握，卻因一時疏忽，竟從雲端「栽」了下來：ㄘㄞˊ\n", "explanation_source": "ai_v1_smoke"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "(A)「揶揄」確讀 ㄧㄝˊ ㄩˊ，意為嘲諷。(B)「晾」讀 ㄌㄧㄤˋ；(C)「藩」讀 ㄈㄢˊ；(D)「栽」讀 ㄗㄞ。"}]'::jsonb) AS t(
